CREATE TABLE IF NOT EXISTS nodes (
    id SERIAL PRIMARY KEY,
    name VARCHAR(100) NOT NULL,
    zone VARCHAR(20) NOT NULL,
    location_type VARCHAR(20) NOT NULL,
    congestion_factor DECIMAL(10,4) NOT NULL,
    legacy_code VARCHAR(20),
    grid_region VARCHAR(20)
);

CREATE TABLE IF NOT EXISTS generators (
    id SERIAL PRIMARY KEY,
    name VARCHAR(100) NOT NULL,
    generator_type VARCHAR(20) NOT NULL,
    capacity_mw DECIMAL(10,2) NOT NULL,
    location_id INTEGER REFERENCES nodes(id),
    commissioned_date DATE,
    is_active BOOLEAN DEFAULT true,
    decommissioned_date DATE,
    meter_type VARCHAR(20),
    original_capacity_mw DECIMAL(10,2),
    last_inspection_date DATE
);

CREATE TABLE IF NOT EXISTS loss_factors (
    id SERIAL PRIMARY KEY,
    zone VARCHAR(20) NOT NULL,
    energy_threshold DECIMAL(10,2) NOT NULL,
    loss_rate DECIMAL(10,6) NOT NULL,
    effective_date DATE NOT NULL,
    superseded_date DATE,
    adjustment_reason TEXT,
    approved_by VARCHAR(20)
);

CREATE TABLE IF NOT EXISTS rate_tiers (
    tier_id SERIAL PRIMARY KEY,
    generator_type VARCHAR(20) NOT NULL,
    min_capacity_factor DECIMAL(10,4),
    location_type VARCHAR(20),
    rate_per_mwh DECIMAL(10,2) NOT NULL,
    priority_order INTEGER NOT NULL,
    effective_date DATE,
    superseded_date DATE,
    tier_code VARCHAR(30)
);

CREATE TABLE IF NOT EXISTS rate_adjustments (
    id SERIAL PRIMARY KEY,
    location_type VARCHAR(20),
    zone VARCHAR(20),
    adjustment_multiplier DECIMAL(6,4),
    effective_date DATE,
    reason TEXT,
    status VARCHAR(20),
    created_by VARCHAR(20),
    approved_by VARCHAR(20)
);

CREATE TABLE IF NOT EXISTS meter_readings (
    id SERIAL PRIMARY KEY,
    generator_id INTEGER,
    timestamp TIMESTAMP NOT NULL,
    energy_mw DECIMAL(12,4) NOT NULL,
    interval_minutes INTEGER NOT NULL,
    quality_flag VARCHAR(20),
    source_system VARCHAR(20)
);

CREATE TABLE IF NOT EXISTS settlements (
    settlement_id SERIAL PRIMARY KEY,
    generator_id INTEGER REFERENCES generators(id),
    period_start TIMESTAMP NOT NULL,
    period_end TIMESTAMP NOT NULL,
    energy_mwh DECIMAL(12,4) NOT NULL,
    gross_payment DECIMAL(12,2) NOT NULL,
    loss_deduction DECIMAL(12,2) NOT NULL,
    congestion_credit DECIMAL(12,2) NOT NULL,
    net_payment DECIMAL(12,2) NOT NULL,
    rate_applied DECIMAL(10,2),
    loss_factor_applied DECIMAL(10,6),
    capacity_factor DECIMAL(10,4)
);

CREATE TABLE IF NOT EXISTS weather_data (
    id SERIAL PRIMARY KEY,
    timestamp TIMESTAMP NOT NULL,
    zone VARCHAR(20) NOT NULL,
    temperature DECIMAL(5,1) NOT NULL,
    demand_factor DECIMAL(6,4) NOT NULL,
    forecast_accuracy DECIMAL(5,4)
);

CREATE TABLE IF NOT EXISTS transmission_upgrades (
    id SERIAL PRIMARY KEY,
    line_id VARCHAR(20) NOT NULL,
    zone VARCHAR(20) NOT NULL,
    upgrade_date DATE NOT NULL,
    capacity_increase DECIMAL(10,2) NOT NULL,
    description TEXT,
    status VARCHAR(20),
    upgrade_category VARCHAR(30),
    affects_loss_factor BOOLEAN,
    cost_million DECIMAL(10,2)
);

CREATE TABLE IF NOT EXISTS meter_firmware_updates (
    id SERIAL PRIMARY KEY,
    generator_id INTEGER REFERENCES generators(id),
    firmware_version VARCHAR(20) NOT NULL,
    update_date DATE NOT NULL,
    notes TEXT,
    update_source VARCHAR(20),
    rollback_available BOOLEAN
);

CREATE TABLE IF NOT EXISTS manual_adjustments (
    id SERIAL PRIMARY KEY,
    generator_id INTEGER REFERENCES generators(id),
    adjustment_date DATE NOT NULL,
    adjustment_amount DECIMAL(12,2),
    reason TEXT,
    status VARCHAR(20),
    resolution_note TEXT,
    submitted_by VARCHAR(20),
    reviewed_by VARCHAR(20)
);

CREATE TABLE IF NOT EXISTS settlement_exceptions (
    id SERIAL PRIMARY KEY,
    exception_start DATE NOT NULL,
    exception_end DATE NOT NULL,
    affected_zone VARCHAR(20),
    description TEXT,
    status VARCHAR(20),
    payment_impact_pct DECIMAL(6,4),
    created_by VARCHAR(20)
);

CREATE INDEX idx_meter_readings_generator ON meter_readings(generator_id);
CREATE INDEX idx_meter_readings_timestamp ON meter_readings(timestamp);
CREATE INDEX idx_settlements_generator ON settlements(generator_id);
CREATE INDEX idx_settlements_period ON settlements(period_start, period_end);
CREATE INDEX idx_weather_zone_time ON weather_data(zone, timestamp);
CREATE INDEX idx_loss_factors_zone ON loss_factors(zone, effective_date);
CREATE INDEX idx_rate_tiers_type ON rate_tiers(generator_type, priority_order);
CREATE INDEX idx_manual_adj_gen ON manual_adjustments(generator_id);






